import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridClient, models
from msal import ConfidentialClientApplication

# Azure Function configuration
def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Managed Identity setup
    tenant_id = 'your_tenant_id'
    client_id = 'your_client_id'
    app_secret = 'your_app_secret'

    authority = f'https://{tenant_id}.onmicrosoft.com/{client_id}'

    ccal = ConfidentialClientApplication(
        client_id=client_id,
        authority=authority,
        client_credential=app_secret
    )

    # Get access token for Azure services
    result = ccal.acquire_token_for_client(scopes=['https://storage.azure.com/.default',
                                                    'https://cosmos.azure.com/.default',
                                                    'https://eventgrid.azure.com/.default'])

    # Blob Storage configuration
    blob_account_name = 'your_blob_storage_account'
    blob_account_key = 'your_blob_storage_account_key'

    blob_service_client = BlobServiceClient.from_connection_string(
        f'DefaultEndpointsProtocol=https;AccountName={blob_account_name};AccountKey={blob_account_key}',
        blob_account_name
    )

    # Cosmos DB configuration
    cosmos_account_name = 'your_cosmos_db_account'
    cosmos_account_key = 'your_cosmos_db_account_key'

    cosmos_client = CosmosClient(
        f'https://{cosmos_account_name}.documents.azure.com:443/',
        credential=cosmos_account_key
    )

    # Event Grid configuration
    event_grid_subscription_id = 'your_event_grid_subscription_id'
    event_grid_resource_group = 'your_event_grid_resource_group'
    event_grid_topic_name = 'your_event_grid_topic_name'

    event_grid_client = EventGridClient(subscription_id=event_grid_subscription_id,
                                        resource_group_name=event_grid_resource_group)

    # Process files from Blob Storage
    container_name = 'your_container_name'
    blob_list = list(blob_service_client.get_blob_client(container=container_name).list_blobs())

    for blob in blob_list:
        logging.info(f'Processing file: {blob.name}')

        # Read file content from Blob Storage
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob.name)
        file_content = blob_client.download_blob().content_as_text()

        # Write results to Cosmos DB
        database_name = 'your_database_name'
        container_name = 'your_container_name'

        cosmos_db_client = cosmos_client.get_database_client(database_name)
        container_client = cosmos_db_client.get_container_client(container_name)

        item_body = {
            'id': blob.name,
            'content': file_content
        }

        container_client.upsert_item(item=item_body)

    # Send notifications via Event Grid
    event_grid_topic = models.EventGridTopic(
        id=event_grid_topic_name,
        location='global',
        type=models.ResourceType.TOPIC,
        properties={
            'name': event_grid_topic_name,
            'type': 'Microsoft.EventGrid/topics'
        }
    )

    event_grid_client.create_topic(topic=event_grid_topic)

    return func.HttpResponse(f'File processing completed successfully.', status_code=200)